import React from 'react';
import { NavLink } from 'react-router-dom';

const navigation = () => {
    return (
        <div className="navigation nav-section sticky-top p-3 w-100">
            <ul className="m-0 p-0">
            <NavLink exact = "true" to="/" className={({isActive}) => isActive ? "nav-active" : "nav-item bg-img-custom me-auto"} className="a" >
                Menu
            </NavLink>
            <NavLink exact = "true" to="/" className={({isActive}) => isActive ? "nav-active" : "nav-item bg-img-custom me-auto"} className="a" >
                Menu
            </NavLink>
            </ul>
        </div>
    );
};

export default navigation;
